INSERT INTO `faqs` VALUES (89,'1','[\"How can I book an appointment with an Immunologist in Lahore?\",\"to book an appointment with a top Immunologist in Lahore. Or, you can also call at 0345-0435621 from 9AM to 11PM to book your appointment.\",\"Are there any additional charges to book an appointment with an Immunologist in Lahore through oladoc?\",\"There are no additional charges when you book through site\",\"What does an Immunologist do?\",\"Vaccinologists are considered experts in the fields of negative-strand RNA viruses and the design and development of viral vaccines. oladoc can help book an appointment with a vaccinologist in Lahore and has specialists across Lahore in areas such as Johar Town, Shadman, Jail Road, Gulberg, New Garden Town and so on. Patients can call us at 0345-0435621 to book an appointment with a specialist for their needs. Patients can also book an online doctor video consultation with top immunologists all across the country. Top vaccinologists practicing in Lahore include . Vaccinologists are also qualified to design schedule of vaccinations and also monitor the health conditions of patients to identify the right time of vaccination.\"]','2020-06-30 04:53:33','2020-06-30 04:53:33'),(90,'1','[\"How can I book an appointment with an Anesthesiologist ?\",\"to book an appointment with a top Anesthesiologist in Lahore. Or, you can also call at 0345-0435621 from 9AM to 11PM to book your appointment.\",\"What is the fee range of top Anesthesiologist\",\"The fee for top Anesthesiologist in Lahore ranges from 1500 to 3000. You will pay at the reception when you visit the doctor.\",\"Are there any additional charges to book an appointment with an Anesthesiologist in Lahore through site?\",\"There are no additional charges when you book through site\"]','2020-06-30 04:56:37','2020-06-30 04:56:37'),(91,'1','[\"How can I book an appointment with a Dermatologist?\",\"to book an appointment with a top Dermatologist in Lahore. Or, you can also call a