INSERT INTO `pages` VALUES (6,'About us','about-us','<h2 class=\"h4\" style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 0.5rem; font-family: \'Open Sans\', Arial, sans-serif; font-weight: 500; line-height: 1.2; color: #232426; font-size: 1.5rem;\">About DoctorFindy</h2>\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: #232426; font-family: \'Open Sans\', Arial, sans-serif; font-size: 16px;\">DoctorFindy is Pakistan&rsquo;s premier digital healthcare platform that aims to revolutionize the local healthcare market. It connects patients with the right doctors and enables the doctors to optimize their medical practices via their practice management software. Patients can use DoctorFindy&nbsp;(web or mobile app) for the online doctor appointment, e-consultation and online lab tests. On the other hand, the doctors can manage their appointments, automate their scheduling, manage medical records, and process billing.</p>','a:2:{s:8:\"seo_desc\";N;s:9:\"show_page\";s:5:\"false\";}',0,'2020-04-15 14:54:43','2020-04-15 14:56:02'),(8,'a','aas','<p>as</p>','a:2:{s:8:\"seo_desc\";s:2:\"as\";s:9:\"show_page\";s:4:\"true\";}',0,'2020-07-10 07:37:52','2020-07-10 07:37:52'),(9,'df','df','<p>df</p>','a:2:{s:8:\"seo_desc\";N;s:9:\"show_page\";s:4:\"true\";}',0,'2020-07-10 07:44:47','2020-07-10 07:44:47');
