-05:16 pm\":{\"space\":\"2\"},\"05:16 pm-05:41 pm\":{\"space\":\"2\"},\"05:41 pm-06:06 pm\":{\"space\":\"2\"},\"06:06 pm-06:31 pm\":{\"space\":\"2\"},\"06:31 pm-06:56 pm\":{\"space\":\"2\"},\"06:56 pm-07:21 pm\":{\"space\":\"2\"},\"07:21 pm-07:46 pm\":{\"space\":\"2\"},\"07:46 pm-08:11 pm\":{\"space\":\"2\"}},\"consultation_fee\":\"300\"},\"consultation_fee\":\"300\"}','message','pending','2020-09-17 06:44:51','2020-09-17 06:44:51'),(205,'267',222,'{\"services\":{\"speciality\":[{\"speciality_id\":\"30\",\"speciality_services\":[{\"service\":\"25\",\"price\":\"400\"}]},{\"speciality_id\":\"1\"}]},\"days\":[\"tue\",\"sat\",\"sun\"],\"tue\":{\"start_time\":\"1:46 pm\",\"end_time\":\"6:6 pm\",\"intervals\":\"10\",\"duration\":\"10\",\"number_of_slots\":\"13\",\"spaces\":\"2\",\"slots\":{\"1:46 pm-02:06 pm\":{\"space\":\"2\"},\"02:06 pm-02:26 pm\":{\"space\":\"2\"},\"02:26 pm-02:46 pm\":{\"space\":\"2\"},\"02:46 pm-03:06 pm\":{\"space\":\"2\"},\"03:06 pm-03:26 pm\":{\"space\":\"2\"},\"03:26 pm-03:46 pm\":{\"space\":\"2\"},\"03:46 pm-04:06 pm\":{\"space\":\"2\"},\"04:06 pm-04:26 pm\":{\"space\":\"2\"},\"04:26 pm-04:46 pm\":{\"space\":\"2\"},\"04:46 pm-05:06 pm\":{\"space\":\"2\"},\"05:06 pm-05:26 pm\":{\"space\":\"2\"},\"05:26 pm-05:46 pm\":{\"space\":\"2\"},\"05:46 pm-06:06 pm\":{\"space\":\"2\"}},\"consultation_fee\":\"400\"},\"sat\":{\"start_time\":\"1:46 pm\",\"end_time\":\"6:6 pm\",\"intervals\":\"10\",\"duration\":\"10\",\"number_of_slots\":\"13\",\"spaces\":\"2\",\"slots\":{\"1:46 pm-02:06 pm\":{\"space\":\"2\"},\"02:06 pm-02:26 pm\":{\"space\":\"2\"},\"02:26 pm-02:46 pm\":{\"space\":\"2\"},\"02:46 pm-03:06 pm\":{\"space\":\"2\"},\"03:06 pm-03:26 pm\":{\"space\":\"2\"},\"03:26 pm-03:46 pm\":{\"space\":\"2\"},\"03:46 pm-04:06 pm\":{\"space\":\"2\"},\"04:06 pm-04:26 pm\":{\"space\":\"2\"},\"04:26 pm-04:46 pm\":{\"space\":\"2\"},\"04:46 pm-05:06 pm\":{\"space\":\"2\"},\"05:06 pm-05:26 pm\":{\"space\":\"2\"},\"05:26 pm-05:46 pm\":{\"space\":\"2\"},\"05:46 pm-06:06 pm\":{\"space\":\"2\"}},\"consultation_fee\":\"400\"},\"sun\":{\"start_time\":\"1:46 pm\",\"end_time\":\"6:6 pm\",\"intervals\":\"10\",\"duration\":\"10\",\"number_of_slots\":\"13\",\"spaces\":\"2\",\"slots\":{\"1:46 pm-02:06 pm\":{\"space\":\"2\"},\"02:06 pm-02:26 pm\":{\"space\":\"2\"},\"02:26 pm-02:46 pm\":{\"space\":\"2\"},\"02:46 pm-03:06 pm\":{\"space\":\"2\"},\"03:06 pm-03:26 pm\":{\"space\":\"2\"},\"03:26 pm-03:46 pm\":{\"space\":\"2\"},\"03:46 pm-04:06 pm\":{\"space\":\"2\"},\"04:06 pm-04:26 pm\":{\"space\":\"2\"},\"04:26 pm-04:46 pm\":{\"space\":\"2\"},\"04:46 pm-05:06 pm\":{\"space\":\"2\"},\"05:06 pm-05:26 pm\":{\"space\":\"2\"},\"05:26 pm-05:46 pm\":{\"space\":\"2\"},\"05:46 pm-06:06 pm\":{\"space\":\"2\"}},\"consultation_fee\":\"400\"},\"consultation_fee\":\"400\"}','message','pending','2020-09-17 06:45:13','2020-09-17 06:45:13');
